class Solution:
    def maxConsecutiveAnswers(self, answerKey: str, k: int) -> int:
        n = len(answerKey)
        left = 0
        right = 0
        max_consecutive = 0
        count_diff = 0
        while right < n:
            if answerKey[right] != 'T':
                count_diff += 1
            if count_diff > k:
                if answerKey[left] != 'T':
                    count_diff -= 1
                left += 1
            max_consecutive = max(max_consecutive, right - left + 1)
            right += 1
        return max_consecutive
